import styles from './AuctionDetailsCard.module.scss';
import { login, leiloesService } from "../../services/api";
import { use, useEffect, useState } from 'react';
import { useLocation } from 'react-router-dom';

const icons = {
  gauge: (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M12 2a10 10 0 1 0 10 10"/><path d="M12 6v6l4 2"/>
    </svg>
  ),
  fuel: (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M3 22V7l9-5 9 5v15"/><path d="M3 11h18"/><path d="M12 22V11"/>
    </svg>
  ),
  calendar: (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <rect x="3" y="4" width="18" height="18" rx="2"/><path d="M16 2v4M8 2v4M3 10h18"/>
    </svg>
  ),
  tag: (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M20.59 13.41l-7.17 7.17a2 2 0 0 1-2.83 0L2 12V2h10l8.59 8.59a2 2 0 0 1 0 2.82z"/><line x1="7" y1="7" x2="7.01" y2="7"/>
    </svg>
  ),
  id: (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <rect x="2" y="5" width="20" height="14" rx="2"/><path d="M8 10h8M8 14h5"/>
    </svg>
  ),
  leilao: (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M3 3l7.07 16.97 2.51-7.39 7.39-2.51L3 3z"/><path d="M13 13l6 6"/>
    </svg>
  ),
  check: (
    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
      <polyline points="20 6 9 17 4 12"/>
    </svg>
  ),
  x: (
    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
      <line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>
    </svg>
  ),
  dash: (
    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
      <line x1="5" y1="12" x2="19" y2="12"/>
    </svg>
  ),
};

const StatusBadge = ({ value, label }) => {
  if (value === null || value === undefined) {
    return (
      <div className="badge badge-null">
        <span className="badge-icon">{icons.dash}</span>
        <span>{label}</span>
      </div>
    );
  }
  const isTrue = value === 1 || value === true || value === "1";
  return (
    <div className={`badge ${isTrue ? "badge-yes" : "badge-no"}`}>
      <span className="badge-icon">{isTrue ? icons.check : icons.x}</span>
      <span>{label}</span>
    </div>
  );
};

const InfoChip = ({ icon, label, value }) => (
  <div className="info-chip">
    <span className="chip-icon">{icon}</span>
    <div className="chip-content">
      <span className="chip-label">{label}</span>
      <span className="chip-value">{value}</span>
    </div>
  </div>
);

const [tab, setTab] = useState("geral");
const tabs = ["geral", "opcionais", "documentos"];

export default function AuctionDetailsCard({id}){

    const [lotes, setLotes] = useState([]);
    const [loading, setLoading] = useState(true);
    const [erro, setErro] = useState(null);
    const location = useLocation();
    const leilao = location.state?.leilaoData;

    useEffect(() => {
        async function carregarDados() {
            try {
            setLoading(true);
            const tokenAtual = localStorage.getItem('@Leiloes:token');
            if (!tokenAtual) {
                await login();
            }
            
            const response = await leiloesService.obterLotes(id);
            setLotes(response.data);
    
            
            } catch (err) {
            setErro('Falha ao carregar os leilões. Verifique o console.');
            console.error(err);
            } finally {
            setLoading(false);
            }
        }
    
        carregarDados();
        }, []);

        console.log(lotes)

        return (
            <div className="vc-page">
        <div className="vc-card">

          {/* LEFT */}
          <div className="vc-left">
            <div className="vc-badge-row">
              <span className="vc-tipo">{v.tipo.replace(/_/g, " ")}</span>
              <span className="vc-id-pill">#ID {v.id}</span>
            </div>

            <div className="vc-title">{v.marca} {v.modelo}</div>
            <div className="vc-subtitle">
              {v.ano_modelo}/{v.ano_fabricacao} · {v.combustivel}
            </div>

            <div className="chips-grid">
              <InfoChip icon={icons.gauge}    label="Quilometragem" value={`${v.km.toLocaleString("pt-BR")} km`} />
              <InfoChip icon={icons.fuel}     label="Combustível"   value={v.combustivel} />
              <InfoChip icon={icons.calendar} label="Ano Modelo"    value={`${v.ano_modelo}/${v.ano_fabricacao}`} />
              <InfoChip icon={icons.tag}      label="Câmbio"        value={v.automatico ? "Automático" : "Manual"} />
              <InfoChip icon={icons.leilao}   label="Leilão"        value={`#${v.leilao_id}`} />
              <InfoChip icon={icons.id}       label="Item ID"       value={`#${v.id}`} />
            </div>
          </div>

          {/* RIGHT */}
          <div className="vc-right">
            <div className="vc-tabs">
              {tabs.map((t) => (
                <button
                  key={t}
                  className={`tab-btn${tab === t ? " active" : ""}`}
                  onClick={() => setTab(t)}
                >
                  {t}
                </button>
              ))}
            </div>

            <div className="tab-body">
              {tab === "geral" && (
                <div className="badge-grid">
                  <StatusBadge value={v.ligando}        label="Ligando" />
                  <StatusBadge value={v.ar}             label="Ar-condicionado" />
                  <StatusBadge value={v.direcao}        label="Direção" />
                  <StatusBadge value={v.estepe}         label="Estepe" />
                  <StatusBadge value={v.vidro_eletrico} label="Vidro Elétrico" />
                  <StatusBadge value={v.automatico}     label="Automático" />
                  <StatusBadge value={v.alagamento}     label="Alagamento" />
                  <StatusBadge value={v.kit_gas}        label="Kit Gás" />
                </div>
              )}

              {tab === "opcionais" && (
                <div className="badge-grid">
                  <StatusBadge value={v.blindagem}               label="Blindagem" />
                  <StatusBadge value={v.chave}                   label="Chave" />
                  <StatusBadge value={v.manual_proprietario}     label="Manual" />
                  <StatusBadge value={v.parabrisa_original}      label="Parabrisa Original" />
                  <StatusBadge value={v.vidro_traseiro_original} label="Vidro Traseiro" />
                  <StatusBadge value={v.chassi_oxidacao}         label="Chassi Oxidação" />
                  <StatusBadge value={v.cambio_obstruido}        label="Câmbio Obstruído" />
                  <StatusBadge value={v.cambio_periciado}        label="Câmbio Periciado" />
                  <StatusBadge value={v.documento_gnv}           label="Doc. GNV" />
                  <StatusBadge value={v.consta_blindagem}        label="Consta Blindagem" />
                </div>
              )}

              {tab === "documentos" && (
                <div className="badge-grid">
                  <StatusBadge value={v.ipva_pago}                 label="IPVA Pago" />
                  <StatusBadge value={v.consta_crlve}              label="Consta CRLVE" />
                  <StatusBadge value={v.consta_sinistro_documento}  label="Sinistro Doc." />
                  <StatusBadge value={v.doc_blindagem}             label="Doc. Blindagem" />
                  <StatusBadge value={v.placa_diverge_documento}   label="Placa Diverge" />
                  <StatusBadge value={v.outro_estado_documento}    label="Outro Estado" />
                  <StatusBadge value={v.emissao_laudo_csv}         label="Laudo CSV" />
                </div>
              )}
            </div>
          </div>

        </div>
      </div>
        );
}
